/**
 * === NEW IN PT10 === Reason: Functional E2E tests for WP-002 (GreekEstherTemplatePicker wiring +
 * integration into the manage-books Create flow).
 *
 * Feature: manage-books Work Package: WP-002 — GreekEstherTemplatePicker wiring + web-view +
 * Create-flow integration Generated by: ui-test-writer (RED phase — every test uses test.fixme)
 *
 * Scope (per strategic-plan-ui.md WP-002):
 *
 * - Web view + provider for the picker (`greek-esther-template-picker.web-view.tsx` and
 *   `.web-view-provider.ts`) under `extensions/src/platform-scripture/`.
 * - Create-flow integration: when ManageBooksDialog Create-mode submit detects ESG selected AND
 *   `creationMethod === 'fromTemplate'`, the picker opens as a modal-on-modal sub-dialog, awaits
 *   user selection, then routes the chosen template into `manageBooks.createBooks(...)`.
 * - Default selection is `'lxx'` (Septuagint) per RF-UI-006 (closed 2026-05-01 — PT9 default verified
 *   from CreateESGForm.Designer.cs `optLXX.Checked = true`). The component default change
 *   (`'modern_scholars'` → `'lxx'`) lands in WP-002's first wiring chunk.
 *
 * Selectors:
 *
 * No `data-testid` values exist on `greek-esther-template-picker.component.tsx` today (read at
 * RED-write time, 2026-05-01). The picker is a Radix `<Dialog>` with `<RadioGroup>` + `<Button>`s,
 * so all selectors here are role/name/aria-label based, which is the preferred form anyway. If the
 * wiring phase (component-builder) adds testids, these tests can be tightened.
 *
 * The picker is invoked from the manage-books web view (Tools > Manage books...). The unified
 * dialog itself is wired in WP-001; this file's tests therefore depend on WP-001's wiring (menu
 * entry, project selector, action toggle, book-grid pills, create-method dropdown) being in place.
 * While both work packages are in RED phase together, every test below is `test.fixme()` and will
 * be activated by component-builder once both WPs land in the IUG loop.
 *
 * Convention note: in Platform.Bible's React tree the picker may render directly inside the
 * manage-books web-view iframe (the parent dialog is rendered from the same web view). All
 * selectors below scope through the manage-books web view's iframe via
 * `frameLocator('iframe[title*="Manage Books" i]')`. If the wiring phase puts the picker in a
 * separate iframe, only the frame selector needs to change.
 */
import { test, expect } from '../../fixtures/cdp.fixture';
import { waitForAppReady } from '../../fixtures/helpers';

const EVIDENCE_DIR = 'proofs/component-evidence/WP-002';
const MANAGE_BOOKS_FRAME = 'iframe[title*="Manage Books" i]';

test.describe('Manage Books — Greek Esther Template Picker (WP-002)', () => {
  /**
   * Close all non-Home tabs before each test so dock layout state from a previous test does not
   * leak in (Platform.Bible persists dock layout per user-data dir).
   */
  test.beforeEach(async ({ mainPage }) => {
    const staleCloseBtn = mainPage
      .locator('.dock-tab')
      .filter({ hasNotText: 'Home' })
      .locator('.dock-tab-close-btn');
    // Bounded loop (worst-case ~8 stale tabs); each iteration must run sequentially so the
    // dock can re-render between clicks. Iteration count is capped to keep the eslint
    // `no-await-in-loop` rule happy (see WP-001 spec for the same pattern).
    for (let attempt = 0; attempt < 8; attempt += 1) {
      // Intentional sequential await: count() must complete before we decide to break.
      // eslint-disable-next-line no-await-in-loop
      const remaining = await staleCloseBtn.count();
      if (remaining === 0) break;
      // Closing a tab re-renders the dock, so we await each click before the next pass.
      // eslint-disable-next-line no-await-in-loop
      await staleCloseBtn.first().dispatchEvent('click');
      // Brief settle to let React commit the dock-layout state change.
      // eslint-disable-next-line no-await-in-loop
      await mainPage.waitForTimeout(500);
    }
  });

  /**
   * Helper sketch for the picker-open path. Phase 3 UI implementations may diverge in menu
   * placement and project-selector wiring; the comments here describe the user-visible flow that
   * the wiring phase MUST realize.
   *
   * Steps the wiring phase must support:
   *
   * 1. `Tools > Manage books...` menu entry opens the manage-books web view (WP-001 wiring).
   * 2. The manage-books web view loads with a project selected (default = active project).
   * 3. User switches to Create action mode.
   * 4. User selects the ESG book pill (Esther — Greek).
   * 5. User picks the "Based on..." (`fromTemplate`) creation method.
   * 6. User clicks the apply button.
   * 7. The picker opens as modal-on-modal — focus moves into the picker, parent dialog stays rendered
   *    behind the picker overlay.
   */

  // ═══════════════════════════════════════════════════════════════════════════
  // Category 1: Navigation — opening the picker from the Create flow
  // ═══════════════════════════════════════════════════════════════════════════

  // @scenario TS-WP-002-derived (acceptance criterion: picker opens from Create flow when
  //                              ESG + fromTemplate is selected; references TS-079 / BHV-407)
  test.fixme(
    'should open picker when user submits Create with ESG selected and fromTemplate method',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // 1. Open Tools > Manage books...
      await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
      await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();

      // 2. Wait for the manage-books tab to appear and switch into its iframe
      const tab = mainPage.locator('.dock-tab', { hasText: /Manage Books/i });
      await expect(tab).toBeVisible({ timeout: 15_000 });
      const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);

      // 3. Switch to Create action mode
      await frame.getByRole('button', { name: /^Create$/i }).click();

      // 4. Click the ESG book pill (Esther — Greek)
      await frame.getByRole('button', { name: /^ESG$/i }).click();

      // 5. Choose the "Based on..." (fromTemplate) creation method
      //    The exact label / role depends on the cherry-pick component but the `fromTemplate`
      //    method is described in ui-spec-manage-books.md as "Based on...".
      await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
      await frame.getByRole('option', { name: /Based on|Reference text|From template/i }).click();

      // 6. Click the apply button — this triggers the Create-flow detection of ESG + fromTemplate
      //    and MUST open the Greek Esther Template Picker as modal-on-modal.
      await frame.getByRole('button', { name: /Create .* in /i }).click();

      // 7. Verify the picker dialog appears with its accessible title
      const picker = frame.getByRole('dialog', { name: /Greek Esther/i });
      await expect(picker).toBeVisible({ timeout: 10_000 });

      // EVD: picker initial open
      await mainPage.screenshot({
        path: `${EVIDENCE_DIR}/EVD-WP002-001-picker-initial-open.png`,
      });
    },
  );

  // ═══════════════════════════════════════════════════════════════════════════
  // Category 2: Render — picker structure and default selection
  // ═══════════════════════════════════════════════════════════════════════════

  // @scenario TS-WP-002-derived (acceptance: dialog title, description, 3 radio options,
  //                              OK/Cancel buttons, radio-group aria-label all render)
  test.fixme(
    'should render dialog title, description, three radio options, and OK/Cancel buttons',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // (Open the picker via the Create flow — abbreviated; see the navigation test above.)
      await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
      await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();
      const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);
      await frame.getByRole('button', { name: /^Create$/i }).click();
      await frame.getByRole('button', { name: /^ESG$/i }).click();
      await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
      await frame.getByRole('option', { name: /Based on|Reference text|From template/i }).click();
      await frame.getByRole('button', { name: /Create .* in /i }).click();

      const picker = frame.getByRole('dialog', { name: /Greek Esther/i });
      await expect(picker).toBeVisible({ timeout: 10_000 });

      // Title (DialogTitle)
      await expect(picker.getByText('Greek Esther: Choose Template')).toBeVisible();

      // Description (DialogDescription) — match the leading sentence to avoid coupling to
      // future copy-edits while still proving the description rendered.
      await expect(picker.getByText(/ESG contains material from the Hebrew text/i)).toBeVisible();

      // Radio group with the documented aria-label (RF-UI-006-aligned)
      const group = picker.getByRole('radiogroup', { name: /Greek Esther template options/i });
      await expect(group).toBeVisible();

      // Three radio options with the PT9-aligned labels
      await expect(group.getByRole('radio', { name: /Septuagint \(LXX\)/i })).toBeVisible();
      await expect(group.getByRole('radio', { name: /^Vulgate/i })).toBeVisible();
      await expect(group.getByRole('radio', { name: /Modern Scholars/i })).toBeVisible();

      // OK + Cancel buttons in the footer
      await expect(picker.getByRole('button', { name: /^OK$/i })).toBeVisible();
      await expect(picker.getByRole('button', { name: /^Cancel$/i })).toBeVisible();
    },
  );

  // @scenario TS-WP-002-derived (acceptance: default selection is Septuagint (LXX) per RF-UI-006)
  test.fixme(
    'should pre-select Septuagint (LXX) as the default option (PT9 parity, RF-UI-006)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
      await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();
      const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);
      await frame.getByRole('button', { name: /^Create$/i }).click();
      await frame.getByRole('button', { name: /^ESG$/i }).click();
      await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
      await frame.getByRole('option', { name: /Based on|Reference text|From template/i }).click();
      await frame.getByRole('button', { name: /Create .* in /i }).click();

      const picker = frame.getByRole('dialog', { name: /Greek Esther/i });
      await expect(picker).toBeVisible({ timeout: 10_000 });

      // The LXX radio MUST be the checked option on initial open. PT9 default verified
      // from CreateESGForm.Designer.cs (optLXX.Checked = true) — RF-UI-006 closed 2026-05-01.
      const lxx = picker.getByRole('radio', { name: /Septuagint \(LXX\)/i });
      const vulgate = picker.getByRole('radio', { name: /^Vulgate/i });
      const modernScholars = picker.getByRole('radio', { name: /Modern Scholars/i });
      await expect(lxx).toBeChecked();
      await expect(vulgate).not.toBeChecked();
      await expect(modernScholars).not.toBeChecked();

      // EVD: default LXX selected on open
      await mainPage.screenshot({
        path: `${EVIDENCE_DIR}/EVD-WP002-002-default-lxx-selected.png`,
      });
    },
  );

  // ═══════════════════════════════════════════════════════════════════════════
  // Category 3: Data Wiring — selection routes through to createBooks
  // ═══════════════════════════════════════════════════════════════════════════

  // @scenario TS-WP-002-derived (acceptance: OK calls onSelect with chosen template;
  //                              wiring layer forwards the choice into createBooks)
  test.fixme(
    'should close the picker and proceed with create flow when user clicks OK with default LXX',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
      await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();
      const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);
      await frame.getByRole('button', { name: /^Create$/i }).click();
      await frame.getByRole('button', { name: /^ESG$/i }).click();
      await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
      await frame.getByRole('option', { name: /Based on|Reference text|From template/i }).click();
      await frame.getByRole('button', { name: /Create .* in /i }).click();

      const picker = frame.getByRole('dialog', { name: /Greek Esther/i });
      await expect(picker).toBeVisible({ timeout: 10_000 });

      // Click OK — the wiring layer's onSelect resolves the parent's onOpenEstherPicker promise,
      // which then drives the createBooks(...) call.
      await picker.getByRole('button', { name: /^OK$/i }).click();

      // The picker MUST close (modal-on-modal pattern: picker dismisses, parent dialog remains).
      await expect(picker).toBeHidden({ timeout: 5_000 });

      // The parent ManageBooksDialog should still be visible (modal-on-modal — only the inner
      // dialog dismissed). We assert the action toggle remains visible inside the parent frame.
      await expect(frame.getByRole('button', { name: /^Create$/i })).toBeVisible();
    },
  );

  // ═══════════════════════════════════════════════════════════════════════════
  // Category 4: Interaction — selecting each of the 3 templates
  // ═══════════════════════════════════════════════════════════════════════════

  // @scenario TS-WP-002-derived (acceptance: user can select Vulgate; selection state updates)
  test.fixme('should let user select Vulgate option', async ({ mainPage }) => {
    await waitForAppReady(mainPage);

    await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
    await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();
    const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);
    await frame.getByRole('button', { name: /^Create$/i }).click();
    await frame.getByRole('button', { name: /^ESG$/i }).click();
    await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
    await frame.getByRole('option', { name: /Based on|Reference text|From template/i }).click();
    await frame.getByRole('button', { name: /Create .* in /i }).click();

    const picker = frame.getByRole('dialog', { name: /Greek Esther/i });
    await expect(picker).toBeVisible({ timeout: 10_000 });

    // Click the Vulgate radio
    const vulgate = picker.getByRole('radio', { name: /^Vulgate/i });
    await vulgate.click();

    // Assert Vulgate is now checked, LXX is not
    await expect(vulgate).toBeChecked();
    await expect(picker.getByRole('radio', { name: /Septuagint \(LXX\)/i })).not.toBeChecked();

    // EVD: after Vulgate selection
    await mainPage.screenshot({
      path: `${EVIDENCE_DIR}/EVD-WP002-003-vulgate-selected.png`,
    });
  });

  // @scenario TS-WP-002-derived (acceptance: user can select Modern Scholars; selection updates)
  test.fixme('should let user select Modern Scholars option', async ({ mainPage }) => {
    await waitForAppReady(mainPage);

    await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
    await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();
    const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);
    await frame.getByRole('button', { name: /^Create$/i }).click();
    await frame.getByRole('button', { name: /^ESG$/i }).click();
    await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
    await frame.getByRole('option', { name: /Based on|Reference text|From template/i }).click();
    await frame.getByRole('button', { name: /Create .* in /i }).click();

    const picker = frame.getByRole('dialog', { name: /Greek Esther/i });
    await expect(picker).toBeVisible({ timeout: 10_000 });

    const modernScholars = picker.getByRole('radio', { name: /Modern Scholars/i });
    await modernScholars.click();
    await expect(modernScholars).toBeChecked();

    // EVD: after Modern Scholars selection
    await mainPage.screenshot({
      path: `${EVIDENCE_DIR}/EVD-WP002-004-modern-scholars-selected.png`,
    });
  });

  // @scenario TS-WP-002-derived (acceptance: OK with non-default selection still resolves)
  test.fixme(
    'should close picker when user clicks OK after selecting Vulgate',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
      await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();
      const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);
      await frame.getByRole('button', { name: /^Create$/i }).click();
      await frame.getByRole('button', { name: /^ESG$/i }).click();
      await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
      await frame.getByRole('option', { name: /Based on|Reference text|From template/i }).click();
      await frame.getByRole('button', { name: /Create .* in /i }).click();

      const picker = frame.getByRole('dialog', { name: /Greek Esther/i });
      await expect(picker).toBeVisible({ timeout: 10_000 });

      await picker.getByRole('radio', { name: /^Vulgate/i }).click();
      await picker.getByRole('button', { name: /^OK$/i }).click();

      // Picker dismisses; parent dialog stays
      await expect(picker).toBeHidden({ timeout: 5_000 });
      await expect(frame.getByRole('button', { name: /^Create$/i })).toBeVisible();
    },
  );

  // ═══════════════════════════════════════════════════════════════════════════
  // Category 5: Cancel paths — Cancel button + Escape key + overlay-click
  // ═══════════════════════════════════════════════════════════════════════════

  // @scenario TS-WP-002-derived (acceptance: Cancel calls onCancel; parent Create flow aborts)
  test.fixme(
    'should close picker and abort Create flow when user clicks Cancel',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
      await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();
      const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);
      await frame.getByRole('button', { name: /^Create$/i }).click();
      await frame.getByRole('button', { name: /^ESG$/i }).click();
      await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
      await frame.getByRole('option', { name: /Based on|Reference text|From template/i }).click();
      await frame.getByRole('button', { name: /Create .* in /i }).click();

      const picker = frame.getByRole('dialog', { name: /Greek Esther/i });
      await expect(picker).toBeVisible({ timeout: 10_000 });

      // EVD: picker visible just before Cancel
      await mainPage.screenshot({
        path: `${EVIDENCE_DIR}/EVD-WP002-005-before-cancel.png`,
      });

      await picker.getByRole('button', { name: /^Cancel$/i }).click();

      // Picker dismisses; parent ManageBooksDialog still visible (Create selections preserved)
      await expect(picker).toBeHidden({ timeout: 5_000 });
      await expect(frame.getByRole('button', { name: /^Create$/i })).toBeVisible();

      // The ESG pill should remain selected (Cancel aborts the flow but does not clear selection).
      // Selection state on book pills is reflected via aria-pressed (per WP-001 C2 acceptance).
      await expect(frame.getByRole('button', { name: /^ESG$/i })).toHaveAttribute(
        'aria-pressed',
        'true',
      );

      // EVD: parent dialog after picker cancel
      await mainPage.screenshot({
        path: `${EVIDENCE_DIR}/EVD-WP002-006-after-cancel.png`,
      });
    },
  );

  // @scenario TS-WP-002-derived (acceptance: keyboard Escape dismisses picker)
  test.fixme('should close picker when user presses Escape', async ({ mainPage }) => {
    await waitForAppReady(mainPage);

    await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
    await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();
    const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);
    await frame.getByRole('button', { name: /^Create$/i }).click();
    await frame.getByRole('button', { name: /^ESG$/i }).click();
    await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
    await frame.getByRole('option', { name: /Based on|Reference text|From template/i }).click();
    await frame.getByRole('button', { name: /Create .* in /i }).click();

    const picker = frame.getByRole('dialog', { name: /Greek Esther/i });
    await expect(picker).toBeVisible({ timeout: 10_000 });

    await mainPage.keyboard.press('Escape');

    await expect(picker).toBeHidden({ timeout: 5_000 });
    // Parent dialog still visible — modal-on-modal stacking
    await expect(frame.getByRole('button', { name: /^Create$/i })).toBeVisible();
  });

  // ═══════════════════════════════════════════════════════════════════════════
  // Category 6: Keyboard navigation — arrows + Tab focus
  // ═══════════════════════════════════════════════════════════════════════════

  // @scenario TS-WP-002-derived (acceptance: arrow keys move focus through radio group)
  test.fixme(
    'should support arrow-key navigation through the radio group',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
      await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();
      const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);
      await frame.getByRole('button', { name: /^Create$/i }).click();
      await frame.getByRole('button', { name: /^ESG$/i }).click();
      await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
      await frame.getByRole('option', { name: /Based on|Reference text|From template/i }).click();
      await frame.getByRole('button', { name: /Create .* in /i }).click();

      const picker = frame.getByRole('dialog', { name: /Greek Esther/i });
      await expect(picker).toBeVisible({ timeout: 10_000 });

      // LXX is the default — focus the LXX radio explicitly to set a known starting point.
      const lxx = picker.getByRole('radio', { name: /Septuagint \(LXX\)/i });
      await lxx.focus();
      await expect(lxx).toBeFocused();

      // ArrowDown should advance to Vulgate (Radix RadioGroup handles arrow navigation).
      await mainPage.keyboard.press('ArrowDown');
      const vulgate = picker.getByRole('radio', { name: /^Vulgate/i });
      await expect(vulgate).toBeFocused();
      await expect(vulgate).toBeChecked();

      // ArrowDown advances to Modern Scholars.
      await mainPage.keyboard.press('ArrowDown');
      const modernScholars = picker.getByRole('radio', { name: /Modern Scholars/i });
      await expect(modernScholars).toBeFocused();
      await expect(modernScholars).toBeChecked();

      // ArrowUp returns to Vulgate.
      await mainPage.keyboard.press('ArrowUp');
      await expect(vulgate).toBeFocused();
    },
  );

  // ═══════════════════════════════════════════════════════════════════════════
  // Category 7: Modal-on-modal stacking — focus trap + restore-focus
  // ═══════════════════════════════════════════════════════════════════════════

  // @scenario TS-WP-002-derived (acceptance: focus is trapped inside picker; parent
  //                              dialog interactive elements are not reachable while picker
  //                              is open; matches Radix Dialog defaults)
  test.fixme(
    'should trap focus inside the picker while open (modal-on-modal stacking)',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
      await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();
      const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);
      await frame.getByRole('button', { name: /^Create$/i }).click();
      await frame.getByRole('button', { name: /^ESG$/i }).click();
      await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
      await frame.getByRole('option', { name: /Based on|Reference text|From template/i }).click();
      await frame.getByRole('button', { name: /Create .* in /i }).click();

      const picker = frame.getByRole('dialog', { name: /Greek Esther/i });
      await expect(picker).toBeVisible({ timeout: 10_000 });

      // Tab through every focusable inside the picker and verify focus stays inside.
      // Radix Dialog focus-trap should bounce focus from the last focusable back to the first.
      // Tab sequence: (radio group — single tab stop) → Cancel → OK → wrap back to radio group.
      // We assert that after several Tab presses the active element's accessible name still
      // matches an in-picker element.
      for (let i = 0; i < 5; i += 1) {
        // Intentional sequential keypresses to exercise the focus-trap loop.
        // eslint-disable-next-line no-await-in-loop
        await mainPage.keyboard.press('Tab');
      }

      // Read the focused element's accessible name from inside the picker context.
      const focusedRoleName = await mainPage.evaluate(() => {
        const el = document.activeElement;
        if (!el || !(el instanceof HTMLElement)) return '';
        return (
          el.getAttribute('aria-label') || el.getAttribute('name') || el.textContent || el.tagName
        );
      });
      // Focus must still be on something belonging to the picker (radio, OK, or Cancel),
      // never on a parent-dialog element like the Create-mode toggle button.
      expect(focusedRoleName).toMatch(
        /Septuagint|Vulgate|Modern Scholars|^OK$|^Cancel$|Greek Esther/i,
      );
    },
  );

  // @scenario TS-WP-002-derived (acceptance: focus returns to the apply button after the picker
  //                              closes — Radix Dialog "restore focus on close" default)
  test.fixme(
    'should restore focus to the apply button after the picker closes via Cancel',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
      await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();
      const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);
      await frame.getByRole('button', { name: /^Create$/i }).click();
      await frame.getByRole('button', { name: /^ESG$/i }).click();
      await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
      await frame.getByRole('option', { name: /Based on|Reference text|From template/i }).click();

      const applyButton = frame.getByRole('button', { name: /Create .* in /i });
      await applyButton.click();

      const picker = frame.getByRole('dialog', { name: /Greek Esther/i });
      await expect(picker).toBeVisible({ timeout: 10_000 });

      await picker.getByRole('button', { name: /^Cancel$/i }).click();
      await expect(picker).toBeHidden({ timeout: 5_000 });

      // Focus should return to the apply button that opened the picker (Radix default behavior).
      await expect(applyButton).toBeFocused();
    },
  );

  // ═══════════════════════════════════════════════════════════════════════════
  // Category 8: Edge cases — re-open after Cancel, picker NOT shown without ESG
  // ═══════════════════════════════════════════════════════════════════════════

  // @scenario TS-WP-002-derived (acceptance: re-opening picker resets selection to LXX default —
  //                              `useEffect(() => setSelected(defaultTemplate), [open, default])`
  //                              in greek-esther-template-picker.component.tsx)
  test.fixme(
    'should reset selection to LXX default when picker is re-opened after a Cancel',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
      await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();
      const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);
      await frame.getByRole('button', { name: /^Create$/i }).click();
      await frame.getByRole('button', { name: /^ESG$/i }).click();
      await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
      await frame.getByRole('option', { name: /Based on|Reference text|From template/i }).click();

      // First open: pick Vulgate, then Cancel
      await frame.getByRole('button', { name: /Create .* in /i }).click();
      let picker = frame.getByRole('dialog', { name: /Greek Esther/i });
      await expect(picker).toBeVisible({ timeout: 10_000 });
      await picker.getByRole('radio', { name: /^Vulgate/i }).click();
      await picker.getByRole('button', { name: /^Cancel$/i }).click();
      await expect(picker).toBeHidden({ timeout: 5_000 });

      // Re-open: LXX should be the checked default again (NOT Vulgate from the previous session).
      await frame.getByRole('button', { name: /Create .* in /i }).click();
      picker = frame.getByRole('dialog', { name: /Greek Esther/i });
      await expect(picker).toBeVisible({ timeout: 10_000 });
      await expect(picker.getByRole('radio', { name: /Septuagint \(LXX\)/i })).toBeChecked();
      await expect(picker.getByRole('radio', { name: /^Vulgate/i })).not.toBeChecked();
    },
  );

  // @scenario TS-WP-002-derived (acceptance: picker is NOT shown when Create is submitted
  //                              with ESG but creationMethod !== 'fromTemplate' — only the
  //                              fromTemplate path triggers the Greek-Esther choice)
  test.fixme(
    'should NOT open picker when ESG is selected with creationMethod = empty',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
      await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();
      const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);
      await frame.getByRole('button', { name: /^Create$/i }).click();
      await frame.getByRole('button', { name: /^ESG$/i }).click();

      // Empty-book method (the default) — picker MUST NOT open.
      await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
      await frame.getByRole('option', { name: /Empty/i }).click();
      await frame.getByRole('button', { name: /Create .* in /i }).click();

      // Picker dialog must NOT be present.
      const picker = frame.getByRole('dialog', { name: /Greek Esther/i });
      await expect(picker).toHaveCount(0);
    },
  );

  // @scenario TS-WP-002-derived (acceptance: picker is NOT shown when fromTemplate is selected
  //                              but ESG is NOT among the selected books)
  test.fixme(
    'should NOT open picker when fromTemplate is selected without ESG in the book selection',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
      await mainPage.getByRole('menuitem', { name: /Manage books/i }).click();
      const frame = mainPage.frameLocator(MANAGE_BOOKS_FRAME);
      await frame.getByRole('button', { name: /^Create$/i }).click();

      // Select GEN (not ESG)
      await frame.getByRole('button', { name: /^GEN$/i }).click();
      await frame.getByRole('combobox', { name: /Method|Creation method/i }).click();
      await frame.getByRole('option', { name: /Based on|Reference text|From template/i }).click();
      await frame.getByRole('button', { name: /Create .* in /i }).click();

      // The picker must NOT appear (ESG gate).
      const picker = frame.getByRole('dialog', { name: /Greek Esther/i });
      await expect(picker).toHaveCount(0);
    },
  );
});
